<body>
    <div class="form-container">
        <h2>Registration Form</h2>
        <form id="registrationForm" action="/submit-form" method="post">
            <div class="form-group">
                <label for="firstName">First Name:</label>
                <input type="text" id="firstName" name="firstName" required>
            </div>
            <div class="form-group">
                <label for="lastName">Last Name:</label>
                <input type="text" id="lastName" name="lastName" required>
            </div>
            <div class="form-group">
                <label for="email">Email:</label>
                <input type="email" id="email" name="email" required>
            </div>
            <div class="form-group">
                <label for="password">Password:</label>
                <input type="password" id="password" name="password" required>
            </div>
            <button type="submit">Register</button>
        </form>
    </div>

    <script>
        document.getElementById('registrationForm').addEventListener('submit', function(event) {
            event.preventDefault(); // Prevent the default form submission

            // Capture form data
            const formData = new FormData(this);
            const data = {};
            formData.forEach((value, key) => {
                data[key] = value;
            });

            // Send data to the server using fetch API
            fetch('/submit-form', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(data)
            })
            .then(response => response.json())
            .then(data => {
                console.log('Success:', data);
                alert('Form submitted successfully!');
            })
            .catch((error) => {
                console.error('Error:', error);
                alert('An error occurred while submitting the form.');
            });
        });
    </script>
</body>
</html>
```

### Server-Side (Node.js with Express)

Next, let's set up a server-side script using Node.js and Express to handle the form submission and save the data.

#### Install Dependencies

First, make sure you have Node.js installed. Then, create a new directory for your project and initialize it with npm:

```sh
mkdir registration-form
cd registration-form
npm init -y
```

Install the necessary dependencies:

```sh
npm install express body-parser
```

#### Create the Server Script

Create a file named `server.js` in your project directory and add the following code:

```javascript
const express = require('express');
const bodyParser = require('body-parser');

const app = express();
const port = 3000;

// Middleware to parse JSON bodies
app.use(bodyParser.json());

// Route to handle form submission
app.post('/submit-form', (req, res) => {
    const { firstName, lastName, email, password } = req.body;

    // Save the data to a file or database
    const data = {
        firstName,
        lastName,
        email,
        password
    };

    // For simplicity, we'll log the data to the console
    console.log('Received Data:', data);

    // Optionally, you can save the data to a file or database
    // For example, saving to a file:
    const fs = require('fs');
    fs.writeFile('data.json', JSON.stringify(data, null, 2), (err) => {
        if (err) throw err;
        console.log('Data saved to data.json');
    });

    // Respond to the client
    res.status(200).json({ message: 'Form submitted successfully!' });
});

// Start the server
app.listen(port, () => {
    console.log(`Server running on http://localhost:${port}`);
});
```

### Running the Application

1. **Start the Server**:
   Run the server using Node.js:

   ```sh
   node server.js
   ```

2. **Open the Form in a Browser**:
   Open the HTML file in a browser and fill out the form. When you submit the form, the data will be captured and saved to the console and optionally to a file (`data.json`).

### Summary

- **Client-Side**: We use JavaScript to capture the form data and send it to the server via an AJAX request.
- **Server-Side**: We use Node.js and Express to handle the form submission, process the data, and optionally save it to a file or database.

This setup ensures that the form is user-friendly and the data is securely handled on the server side.
